import jwt from 'jsonwebtoken';
import { Router } from 'express';

const router = Router();
const SECRET = process.env.JWT_SECRET || 'dev-secret';

const users = {
  gilles: { password: process.env.GILLES_PASSWORD || 'Gilles-Prosp2026!', role: 'admin' },
  lea: { password: process.env.LEA_PASSWORD || 'Lea-Prosp2026!', role: 'admin' },
  hugo: { password: process.env.HUGO_PASSWORD || 'Hugo-Prosp2026!', role: 'operator' },
  nina: { password: process.env.NINA_PASSWORD || 'Nina-Prosp2026!', role: 'operator' },
};

router.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).json({ error: 'Identifiants invalides' });
  }
  const token = jwt.sign({ username, role: user.role }, SECRET, { expiresIn: '24h' });
  res.json({ token, role: user.role, username });
});

export function verifyToken(req, res, next) {
  if (req.path === '/api/auth/login') return next();

  const authHeader = req.headers.authorization;
  const token = authHeader?.startsWith('Bearer ') ? authHeader.slice(7) : req.query.token;
  if (!token) return res.status(401).json({ error: 'Token manquant' });

  try {
    req.user = jwt.verify(token, SECRET);
    next();
  } catch {
    res.status(401).json({ error: 'Token invalide ou expir√©' });
  }
}

export default router;

